1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	const DEDUCTIBLE = 100;
11	const CAP_MULTIPLIER = 2;
12	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
13	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE = 0.1;
17	const CURSE_SURCHARGE = 0.5;
18	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const LOYALTY_DISCOUNT = 0.2;
21	const LOYALTY_YEARS_THRESHOLD = 2;
22	const FOLLOWUP_DISCOUNT = 0.15;
23	const COMPONENT_BASE_PREMIUM = 25;
24	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_INSURANCE_VALUE = 250;
27	
28	type Tariff = { base: number; insurance: number };
29	
30	const MAIN_ITEM_TARIFF: Record<string, Tariff> = {
31	  sword: { base: 100, insurance: 1000 },
32	  amulet: { base: 60, insurance: 600 },
33	};
34	
35	const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_TARIFF;
36	
37	const itemInsuranceValue = (item: Item): number =>
38	  MAIN_ITEM_TARIFF[item.type]?.insurance ?? COMPONENT_INSURANCE_VALUE;
39	
40	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
41	
42	const rateAmount = (base: number, applies: boolean, rate: number): number =>
43	  applies ? base * rate : 0;
44	
45	const isHighlyEnchanted = (item: Item): boolean =>
46	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
47	
48	const mainItemBase = (item: Item): number => MAIN_ITEM_TARIFF[item.type].base;
49	
50	const mainItemSurcharges = (item: Item): number => {
51	  const base = mainItemBase(item);
52	  return (
53	    rateAmount(base, item.cursed === true, CURSE_SURCHARGE) +
54	    rateAmount(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE)
55	  );
56	};
57	
58	const componentGroupBase = (count: number): number => {
59	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
60	  const leftover = count % COMPONENT_BLOCK_SIZE;
61	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
62	};
63	
64	const componentCountsByType = (components: Item[]): Map<string, number> => {
65	  const counts = new Map<string, number>();
66	  for (const item of components) {
67	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
68	  }
69	  return counts;
70	};
71	
72	const sumComponentGroupBases = (components: Item[]): number =>
73	  [...componentCountsByType(components).values()].reduce(
74	    (total, count) => total + componentGroupBase(count),
75	    0,
76	  );
77	
78	const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => {
79	  const mainItems: Item[] = [];
80	  const components: Item[] = [];
81	  for (const item of items) {
82	    (isMainItem(item) ? mainItems : components).push(item);
83	  }
84	  return { mainItems, components };
85	};
86	
87	const sumMainItemBases = (mainItems: Item[]): number =>
88	  mainItems.reduce((sum, item) => sum + mainItemBase(item), 0);
89	
90	const sumMainItemSurcharges = (mainItems: Item[]): number =>
91	  mainItems.reduce((sum, item) => sum + mainItemSurcharges(item), 0);
92	
93	const isLoyalCustomer = (customer: Customer): boolean =>
94	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
95	
96	const totalDiscount = (policyBase: number, customer: Customer, isFollowUp: boolean): number =>
97	  rateAmount(policyBase, isLoyalCustomer(customer), LOYALTY_DISCOUNT) +
98	  rateAmount(policyBase, isFollowUp, FOLLOWUP_DISCOUNT);
99	
100	const priceQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => {
101	  const { mainItems, components } = partitionItems(step.items);
102	  const policyBase = sumMainItemBases(mainItems) + sumComponentGroupBases(components);
103	  const surcharges = sumMainItemSurcharges(mainItems);
104	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
105	  const discounts = totalDiscount(policyBase, customer, isFollowUp);
106	  return {
107	    premium: ceilWithEpsilon(policyBase + surcharges + firstInsurance - discounts + PROCESSING_FEE),
108	  };
109	};
110	
111	const countQuotesBefore = (steps: Step[], index: number): number =>
112	  steps.slice(0, index).filter((s) => s.op === "quote").length;
113	
114	const insuranceSumOf = (step: QuoteStep): number =>
115	  step.items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
116	
117	const findInsuredItem = (policyStep: QuoteStep, itemType: string): Item | undefined =>
118	  policyStep.items.find((item) => item.type === itemType);
119	
120	const reimbursementRate = (item: Item | undefined): number =>
121	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
122	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
123	    : 1;
124	
125	const damagePayout = (damage: Damage, policyStep: QuoteStep): number => {
126	  const item = findInsuredItem(policyStep, damage.itemType);
127	  return Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
128	};
129	
130	const totalPayout = (damages: Damage[], policyStep: QuoteStep): number =>
131	  damages.reduce((sum, d) => sum + damagePayout(d, policyStep), 0);
132	
133	const processClaim = (step: ClaimStep, steps: Step[]): { payout: number; remainingCap: number } => {
134	  const policyStep = steps[step.policy] as QuoteStep;
135	  const cap = CAP_MULTIPLIER * insuranceSumOf(policyStep);
136	  const payout = totalPayout(step.incident.damages, policyStep);
137	  return { payout, remainingCap: cap - payout };
138	};
139	
140	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
141	  results: scenario.steps.map((step, i) =>
142	    step.op === "quote"
143	      ? priceQuote(step, scenario.customer, countQuotesBefore(scenario.steps, i) > 0)
144	      : processClaim(step, scenario.steps),
145	  ),
146	});
